mapper.select:
/* SQL ID : SrvyDAO.profSrvyListPaging 설 명 : 교수설문목록페이징 */ WITH SBJCT_USER AS ( SELECT ATNDLC.USER_ID FROM TB_LMS_ATNDLC ATNDLC JOIN TB_LMS_SBJCT SBJCT ON ATNDLC.SBJCT_ID = SBJCT.SBJCT_ID WHERE ATNDLC.AUDITYN = 'N' AND SBJCT.SBJCT_ID = #{sbjctId} ), SUB_SRVY AS ( SELECT SRVY_ID, UP_SRVY_ID FROM TB_LMS_SRVY WHERE DELYN = 'N' AND USEYN = 'Y' AND UP_SRVY_ID IS NOT NULL ), SRVY_BASE AS ( SELECT ROW_NUMBER() OVER (ORDER BY SRVY.SRVY_SDTTM DESC, SRVY.REG_DTTM ASC) AS LINE_NO , COUNT(SRVY.SRVY_ID) OVER () AS TOTAL_CNT , SRVY.SRVY_ID , SRVY.SBJCT_ID , CASE WHEN EXISTS (SELECT 1 FROM SUB_SRVY SS WHERE SS.UP_SRVY_ID = SRVY.SRVY_ID) THEN 'SRVY_TEAM' ELSE 'SRVY' END AS SRVY_GBN , SRVY.SRVY_TTL , SRVY.SRVY_SDTTM , SRVY.SRVY_EDTTM , SRVY.MRK_RFLTYN , SRVY.MRK_RFLTRT , SRVY.MRK_OYN , SRVY.SRVY_QSTNS_CMPTNYN , SRVY.REG_DTTM , (SELECT COUNT(USER_ID) FROM SBJCT_USER) AS SRVY_TRGT_CNT , ( SELECT COUNT(SP.SRVY_PTCP_ID) FROM TB_LMS_SRVY_PTCP SP WHERE SP.USER_ID IN (SELECT USER_ID FROM SBJCT_USER) AND SP.SRVY_ID IN ( SELECT SS.SRVY_ID FROM SUB_SRVY SS WHERE SS.UP_SRVY_ID = SRVY.SRVY_ID UNION ALL SELECT SRVY.SRVY_ID FROM DUAL ) ) AS SRVY_PTCP_CNT , ( SELECT COUNT(SP.SRVY_PTCP_ID) FROM TB_LMS_SRVY_PTCP SP WHERE SP.USER_ID IN (SELECT USER_ID FROM SBJCT_USER) AND SP.SRVY_PTCP_EVLYN = 'Y' AND SP.SRVY_ID IN ( SELECT SS.SRVY_ID FROM SUB_SRVY SS WHERE SS.UP_SRVY_ID = SRVY.SRVY_ID UNION ALL SELECT SRVY.SRVY_ID FROM DUAL ) ) AS SRVY_EVLTEE_CNT FROM TB_LMS_SRVY SRVY JOIN TB_LMS_SBJCT SBJCT ON SRVY.SBJCT_ID = SBJCT.SBJCT_ID WHERE SRVY.SRVY_GBNCD = 'LCTR_SRVY' AND SBJCT.SBJCT_ID = #{sbjctId} AND SRVY.DELYN = 'N' AND SRVY.USEYN = 'Y' AND SRVY.UP_SRVY_ID IS NULL
AND LOWER(SRVY.SRVY_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
) SELECT * FROM SRVY_BASE
AND LINE_NO BETWEEN #{firstIndex} +1 AND #{firstIndex} + #{listScale}

mapper.update:
		/*
             SQL ID : SrvyDAO.srvyMrkRfltrtListModify
             설  명 : 설문성적반영비율목록수정
         */

         UPDATE TB_LMS_SRVY SET
         	  MDFR_ID = #{item.mdfrId}
         	, MOD_DTTM = FN_DTTM()
         	, MRK_RFLTRT = #{item.mrkRfltrt}
          WHERE SRVY_ID = #{item.srvyId}
            AND UP_SRVY_ID IS NULL

mapper.insert:
		/*
             SQL ID : SrvyDAO.srvyRegist
             설  명 : 설문등록
         */
        INSERT INTO TB_LMS_SRVY (
        	  SRVY_ID
			, SRVY_GRP_ID
			, SBJCT_ID
			, LCTR_WKNO_SCHDL_ID
			, UP_SRVY_ID
			, SRVY_WRT_TYCD
			, SRVY_GBNCD
			, SRVY_TYCD
			, SRVY_TRGT_GBNCD
			, SRVY_TTL
			, SRVY_CTS
			, RSLT_OPEN_TYCD
			, DVCLAS_REGYN
			, SRVY_SDTTM
			, SRVY_EDTTM
			, EVL_SCR_TYCD
			, MRK_RFLTYN
			, MRK_RFLTRT
			, MRK_OYN
			, BYTEAM_SUBSRVY_USEYN
			, RGTR_ID
			, REG_DTTM
        ) VALUES (
        	  #{srvyId}
			, #{srvyGrpId}
			, #{sbjctId}
			, #{lctrWknoSchdlId}
			, #{upSrvyId}
			, #{srvyWrtTycd}
			, #{srvyGbncd}
			, #{srvyTycd}
			, #{srvyTrgtGbncd}
			, #{srvyTtl}
			, #{srvyCts}
			, #{rsltOpenTycd}
			, #{dvclasRegyn}
			, #{srvySdttm}
			, #{srvyEdttm}
			, #{evlScrTycd}
			, #{mrkRfltyn}
			, #{mrkRfltrt}
			, #{mrkOyn}
			, #{byteamSubsrvyUseyn}
			, #{rgtrId}
			, FN_DTTM()
        )

mapper.update:
	/*
         SQL ID : SrvyDAO.srvyModify
         설  명  : 설문수정
     */
	UPDATE TB_LMS_SRVY SET
		  MDFR_ID  = #{mdfrId}
		, MOD_DTTM = FN_DTTM()

		, SRVY_GRP_ID = #{srvyGrpId}


		, SBJCT_ID = #{sbjctId}


		, LCTR_WKNO_SCHDL_ID = #{lctrWknoSchdlId}


		, UP_SRVY_ID = #{upSrvyId}


		, SRVY_WRT_TYCD = #{srvyWrtTycd}


		, SRVY_GBNCD = #{srvyGbncd}


		, SRVY_TYCD = #{srvyTycd}


		, SRVY_TRGT_GBNCD = #{srvyTrgtGbncd}


		, SRVY_TTL = #{srvyTtl}


		, SRVY_CTS = #{srvyCts}


		, SRVY_QSTNS_CMPTNYN = #{srvyQstnsCmptnyn}


		, RSLT_OPEN_TYCD = #{rsltOpenTycd}


		, DVCLAS_REGYN = #{dvclasRegyn}


		, SRVY_SDTTM = #{srvySdttm}


		, SRVY_EDTTM = #{srvyEdttm}


		, EVL_SCR_TYCD = #{evlScrTycd}


		, USEYN = #{useyn}


		, DELYN = #{delyn}


		, MRK_RFLTYN = #{mrkRfltyn}


		, MRK_RFLTRT = #{mrkRfltrt}


		, MRK_OYN = #{mrkOyn}


		, BYTEAM_SUBSRVY_USEYN = #{byteamSubsrvyUseyn}

	WHERE SRVY_ID = #{srvyId}

mapper.delete:
		/*
             SQL ID : SrvyDAO.subSrvyDelete
             설  명  : 하위설문삭제
         */
         DELETE FROM TB_LMS_SRVY
          WHERE UP_SRVY_ID = #{srvyId}

mapper.update:
		/*
             SQL ID : SrvyDAO.subSrvyDelynModify
             설  명  : 하위설문삭제여부수정
         */
        UPDATE TB_LMS_SRVY SET
        	  MDFR_ID = #{mdfrId}
        	, MOD_DTTM = FN_DTTM()
        	, DELYN = 'Y'
         WHERE UP_SRVY_ID = #{srvyId}

mapper.select:
/* SQL ID : SrvyDAO.srvyLrnGrpSubAsmtList 설 명 : 설문학습그룹부과제목록조회 */ SELECT TEAM.TEAM_ID , TEAM.TEAMNM , NVL((SELECT USR.USERNM FROM TB_LMS_USER USR JOIN TB_LMS_TEAM_MBR TEAM_MBR ON USR.USER_ID = TEAM_MBR.USER_ID WHERE TEAM_MBR.LDRYN = 'Y' AND TEAM_MBR.TEAM_ID = TEAM.TEAM_ID), '-') AS leaderNm , (SELECT COUNT(tlts.USER_ID) FROM TB_LMS_TEAM_MBR tlts WHERE tlts.TEAM_ID = TEAM.TEAM_ID) AS teamMbrCnt , SRVY.SRVY_TTL , SRVY.SRVY_CTS FROM TB_LMS_TEAM TEAM LEFT JOIN TB_LMS_SRVY_TRGT SRVY_TRGT ON TEAM.TEAM_ID = SRVY_TRGT.TEAM_ID AND SRVY_TRGT.SRVY_ID IN (SELECT SRVY_ID FROM TB_LMS_SRVY WHERE UP_SRVY_ID = #{srvyId}) LEFT JOIN TB_LMS_SRVY SRVY ON SRVY_TRGT.SRVY_ID = SRVY.SRVY_ID AND SRVY.DELYN = 'N' AND SRVY.USEYN = 'Y' AND SRVY.UP_SRVY_ID = #{srvyId} WHERE TEAM.LRN_GRP_ID = #{lrnGrpId}
AND SRVY.UP_SRVY_ID = #{srvyId}
ORDER BY TEAM.TEAM_ID ASC

/* SQL ID : SrvyDAO.profAuthrtSbjctSrvyList 설 명 : 교수권한과목설문목록조회 */ SELECT * FROM ( WITH SUB_SRVY AS ( SELECT SRVY_ID, UP_SRVY_ID FROM TB_LMS_SRVY WHERE DELYN = 'N' AND USEYN = 'Y' AND UP_SRVY_ID IS NOT NULL ) SELECT ROW_NUMBER() OVER(ORDER BY SRVY.SRVY_ID DESC) AS LINE_NO , SRVY.SRVY_ID , SRVY.SRVY_TTL , SBJCT.SBJCT_ID , SBJCT.SBJCTNM , SBJCT.DVCLAS_NO , CASE WHEN EXISTS (SELECT 1 FROM SUB_SRVY SS WHERE SS.UP_SRVY_ID = SRVY.SRVY_ID) THEN 'SRVY_TEAM' ELSE 'SRVY' END AS SRVY_GBN , COUNT(1) OVER() AS TOTAL_CNT FROM TB_LMS_SBJCT_ADM SBJCT_ADM JOIN TB_LMS_SRVY SRVY ON SBJCT_ADM.SBJCT_ID = SRVY.SBJCT_ID AND SRVY.DELYN = 'N' AND SRVY.USEYN = 'Y' JOIN TB_LMS_SBJCT SBJCT ON SBJCT.SBJCT_ID = SRVY.SBJCT_ID LEFT JOIN TB_LMS_SMSTR_CHRT SMSTR_CHRT ON (SBJCT.SMSTR_CHRT_ID = SMSTR_CHRT.SMSTR_CHRT_ID AND SBJCT.SBJCT_REF_TYCD = 'CHRT') WHERE SBJCT_ADM.USER_ID = #{userId} AND SRVY.SRVY_GBNCD = 'LCTR_SRVY' AND SRVY.UP_SRVY_ID IS NULL AND SBJCT_ADM.SBJCT_ADM_TYCD = 'PROF'
AND SBJCT.SMSTR_CHRT_ID = #{smstrChrtId}
AND SBJCT.SBJCT_ID = #{sbjctId}
AND LOWER(SRVY.SRVY_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
ORDER BY SRVY.SRVY_ID ) A WHERE 1=1
AND LINE_NO BETWEEN #{firstIndex} +1 AND #{firstIndex} + #{listScale}
